class Solution:
    def palindromePairs(self, words):
        def is_pal(s):
            return s == s[::-1]
        result = []
        for i in range(len(words)):
            for j in range(len(words)):
                if i != j and is_pal(words[i] + words[j]):
                    result.append([i, j])
        return result

