class Solution:
    def palindromePairs(self, words):
        def is_pal(s):
            return s == s[::-1]
        rev_map = {w[::-1]: i for i, w in enumerate(words)}
        result = []
        for i, w in enumerate(words):
            n = len(w)
            for cut in range(n + 1):
                left, right = w[:cut], w[cut:]
                # case 1: left is palindrome, concat word[j]+word[i]
                if is_pal(left):
                    j = rev_map.get(right)
                    if j is not None and j != i:
                        result.append([j, i])
                # case 2: right is palindrome, concat word[i]+word[j]
                # only for non-empty right to avoid duplicating pairs already found by case1
                if len(right) > 0 and is_pal(right):
                    j = rev_map.get(left)
                    if j is not None and j != i:
                        result.append([i, j])
        return result

