var palindromePairs = function(words) {
    function isPal(s) {
        let l = 0, r = s.length - 1;
        while (l < r) { if (s[l] !== s[r]) return false; l++; r--; }
        return true;
    }
    const revMap = new Map();
    for (let i = 0; i < words.length; i++) {
        revMap.set(words[i].split('').reverse().join(''), i);
    }
    const result = [];
    for (let i = 0; i < words.length; i++) {
        const w = words[i];
        const n = w.length;
        for (let cut = 0; cut <= n; cut++) {
            const left = w.slice(0, cut);
            const right = w.slice(cut);
            if (isPal(left)) {
                const j = revMap.get(right);
                if (j !== undefined && j !== i) result.push([j, i]);
            }
            if (right.length > 0 && isPal(right)) {
                const j = revMap.get(left);
                if (j !== undefined && j !== i) result.push([i, j]);
            }
        }
    }
    return result;
};
